// Calculate next publish time for each unscheduled post
// based on interval_hours and last_scheduled time per platform
const posts = $input.first().json;
const configs = $('Get Platform Schedules').all();
const results = [];

for (const post of $('Get Unscheduled Approved Posts').all()) {
  const config = configs.find(c => c.json.platform === post.json.platform);
  if (!config) continue;

  const intervalMs = (config.json.interval_hours || 8) * 3600000;
  const lastScheduled = new Date(config.json.last_scheduled).getTime();
  const nextSlot = new Date(Math.max(lastScheduled + intervalMs, Date.now() + 300000));

  results.push({
    id: post.json.id,
    platform: post.json.platform,
    scheduled_at: nextSlot.toISOString()
  });

  // Move forward so next post of same platform gets later slot
  config.json.last_scheduled = nextSlot.toISOString();
}

return results.map(r => ({ json: r }));
